class Solution(object):
    def minZeroArray(self, nums, queries):
        n = len(nums)
        m = len(queries)

        def can_zero(k):
            for i in range(n):
                if nums[i] == 0:
                    continue
                target = nums[i]
                vals = [queries[j][2] for j in range(k)
                        if queries[j][0] <= i <= queries[j][1]]
                # Subset-sum: can vals sum to exactly target?
                reachable = {0}
                for v in vals:
                    reachable = reachable | {x + v for x in reachable if x + v <= target}
                if target not in reachable:
                    return False
            return True

        if not can_zero(m):
            return -1

        lo, hi = 0, m
        while lo < hi:
            mid = (lo + hi) // 2
            if can_zero(mid):
                hi = mid
            else:
                lo = mid + 1
        return lo
